            "source": "\"{\"\"process_id\"\":\"\"PROC-1001\"\",\"\"title\"\":\"\"Sales Deal Approval\"\",\n\"\"notification_channel\"\":\"\"\"+in_NotificationChannel+\"\"\",\"\"form_schema\"\":[{\"\"name\"\":\"\"customer_name\"\",\"\"type\"\":\"\"readonly\"\",\"\"label\"\":\"\"Customer Name\"\"},{\"\"name\"\":\"\"deal_amount\"\",\"\"type\"\":\"\"number\"\",\"\"label\"\":\"\"Deal Amount\"\",\"\"required\"\":true,\"\"sensitive\"\":true,\"\"min\"\":1},{\"\"name\"\":\"\"agreement_months\"\",\"\"type\"\":\"\"select\"\",\"\"label\"\":\"\"Agreement (Months)\"\",\"\"required\"\":true,\"\"options\"\":[{\"\"value\"\":\"\"12\"\",\"\"label\"\":\"\"12\"\"},{\"\"value\"\":\"\"24\"\",\"\"label\"\":\"\"24\"\"},{\"\"value\"\":\"\"36\"\",\"\"label\"\":\"\"36\"\"}",
